VALUES
  ('medical-tech-moex-03188', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '檢驗分析中關於醋酸的用途，下列敘述何者錯誤？', '["尿蛋白試驗─加熱及醋酸法，醋酸做為確認是否有尿蛋白", "在尿液檢體中區別酵母菌與紅血球，稀醋酸會使紅血球溶解", "區別尿結晶特性，加入醋酸會使正常的尿酸結晶及重尿酸銨結晶溶解", "糞便總脂肪測定，加入醋酸使三酸甘油脂轉變成脂肪酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03189', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '有關正常成人的體液，下列敘述何者錯誤？', '["尿液的總蛋白濃度為2～10 mg/dL", "腰椎腦脊髓液的總蛋白濃度為15～45 mg/dL", "滑膜液的總蛋白濃度為1～3 g/dL", "滑膜液的葡萄糖濃度為30～50 mg/dL"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03190', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於人類基因體的敘述，下列何者最不適當？', '["與串聯重複（tandem repetitive）DNA相比，散布重複（interspersed repetitive）DNA在人類基因體中 所占的比例較高", "單一核苷酸多型性（SNP）比串聯重複（tandem repetitive）DNA的頻率高", "可轉譯成蛋白質的基因序列約占全基因體序列的20%", "Alu repeat為散布重複（interspersed repetitive）DNA"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 41, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03191', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於細菌Rho–依賴轉錄終止子（Rho-dependent terminators）的敘述，下列何者最不適合？', '["又稱為intrinsic terminators", "此轉錄終止過程不涉及stem loop的形成", "此轉錄終止所需的Rho因子是由 6 個相同蛋白質組成的環狀結構", "Rho因子誘導終止需要來自ATP水解的能量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 42, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03192', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '真核細胞轉譯時，下列那個轉譯起始因子最先結合到 mRNA 的 5’-cap？', '["eIF4A", "eIF4B", "eIF4E", "eIF4G"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 43, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03193', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '哺乳動物粒線體密碼子點突變（point mutation），下列何者不屬於無義突變（nonsense mutation）？', '["UAU＞UAA", "UAC＞UAG", "UGC＞UGA", "AGA＞AGG"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 44, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03194', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列疾病大部分是由於點突變（point mutation）所引起，但何者除外？', '["鐮刀型貧血（sickle cell anemia）", "A 型血友病（hemophilia A）", "G6PD 缺乏症（蠶豆症）", "亨丁頓舞蹈症（Huntington disease）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 45, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03195', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於組織之total RNA萃取的敘述，下列何者最不適當？', '["80～90%的total RNA為ribosomal RNA（rRNA）", "agarose gel electrophoresis可以區分large與small ribosomal RNA", "電泳的移動速度，28S rRNA比18S rRNA快", "玻璃器皿可經4～6小時高溫（400℃）處理，使RNase去活性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 46, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03196', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '臨床上針對腎臟移植的患者會檢測BKV病毒量作監控，下列敘述何者最不適當？', '["採集的檢體可以是血液檢體或尿液檢體", "若採集血液檢體，建議使用heparin作為抗凝劑使用，才不會抑制後續PCR之進行", "血液檢體採集後，應儘快離心，將血漿與血球分離，並將血漿分裝儲存", "萃取後的核酸檢體，建議儲存於-20℃以下冰櫃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03197', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '在進行原位螢光雜交法（fluorescence in situ hybridization, FISH）前須先進行染色體製備，其應在下 列那個細胞分裂時期進行分析最適當？', '["preprophase", "prometaphase", "metaphase", "telophase"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 48, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
